import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions } from 'features/shared/selectOptionHelpers';

export default function WorksPage() {
  const parcelOptions = useParcelOptions();

  return (
    <CrudResourceModule
      title="Obras / Estado Terreno"
      path={API_PATHS.works}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'estado_actual', label: 'Estado actual' },
        { key: 'foco_incendio', label: 'Riesgo incendio' },
        {
          key: 'kpi',
          label: 'KPI',
          render: (row) => <Chip size="small" label={row.kpi || '-'} color={row.kpi === 'PELIGRO' ? 'error' : row.kpi === 'ATENCION' ? 'warning' : 'success'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'deshabitada', label: 'Deshabitada' },
        { name: 'cercada', label: 'Cercada' },
        { name: 'sucia', label: 'Sucia' },
        { name: 'casas', label: 'Casas' },
        { name: 'otra_construccion', label: 'Otra construcción' },
        { name: 'cumplen', label: 'Cumplen' },
        { name: 'cortafuego', label: 'Cortafuego' },
        { name: 'limpieza', label: 'Limpieza' },
        {
          name: 'foco_incendio',
          label: 'Foco/incendio',
          type: 'select',
          options: [
            { value: 'BAJA', label: 'Baja' },
            { value: 'MEDIA', label: 'Media' },
            { value: 'ALTA', label: 'Alta' }
          ]
        },
        { name: 'atributo_kpi', label: 'Atributo KPI', type: 'number' },
        {
          name: 'kpi',
          label: 'KPI',
          type: 'select',
          options: [
            { value: 'NORMAL', label: 'Normal' },
            { value: 'ATENCION', label: 'Atención' },
            { value: 'PELIGRO', label: 'Peligro' }
          ]
        },
        { name: 'estado_actual', label: 'Estado actual' },
        { name: 'rol_sii', label: 'ROL SII' },
        { name: 'certificado_obras', label: 'Certificado obras' },
        { name: 'permiso_dom', label: 'Permiso DOM' },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-updated_at"
    />
  );
}
